PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?poet ?poetLabel
WHERE {
  ?poet wdt:P106 wd:Q49757 ;
        wdt:P21 wd:Q6581072 ;
        wdt:P27 wd:Q11772 .
  ?poet rdfs:label ?poetLabel .
  FILTER (LANG(?poetLabel) = "en")
}
LIMIT 10

